import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom/client";
import {
  Phone,
  Mail,
  MapPin,
  Facebook,
  Instagram,
  ArrowUpRight,
  MessageCircle,
  Copy,
} from "lucide-react";
import "./ContactUs.css";

// --- Custom Icons ---
const WhatsAppIcon = ({ size }) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="currentColor"
